-- 7. PROPERTY BLOCKS (date blocking for manual, airbnb, booking, maintenance)
CREATE TABLE IF NOT EXISTS property_blocks (
  id               BIGINT AUTO_INCREMENT PRIMARY KEY,
  property_id      INT NOT NULL,
  start_date       DATE NOT NULL,
  end_date         DATE NOT NULL,
  block_type       VARCHAR(50) NOT NULL
                   CHECK (block_type IN ('manual', 'airbnb', 'booking', 'maintenance')),
  source_reference VARCHAR(255),
  notes            TEXT,
  created_at       TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at       TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,

  CONSTRAINT fk_property_blocks_property
      FOREIGN KEY (property_id) REFERENCES properties(id) ON DELETE CASCADE,
  CONSTRAINT end_after_start CHECK (end_date >= start_date),
  CONSTRAINT valid_block_range CHECK (DATEDIFF(end_date, start_date) <= 730) -- max 2 years
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_property_blocks_property_dates
  ON property_blocks (property_id, start_date, end_date);
CREATE INDEX idx_property_blocks_type
  ON property_blocks (property_id, block_type);


-- 8. PROPERTY ICAL SOURCES (iCal feed URLs for syncing)
CREATE TABLE IF NOT EXISTS property_ical_sources (
  id               BIGINT AUTO_INCREMENT PRIMARY KEY,
  property_id      INT NOT NULL,
  provider         VARCHAR(50) NOT NULL
                   CHECK (provider IN ('airbnb', 'booking', 'vrbo')),
  ical_url         TEXT NOT NULL,
  last_sync_at     TIMESTAMP NULL,
  created_at       TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at       TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,

  CONSTRAINT fk_property_ical_sources_property
      FOREIGN KEY (property_id) REFERENCES properties(id) ON DELETE CASCADE,
  CONSTRAINT unique_provider_per_property UNIQUE (property_id, provider)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_property_ical_sources_property
  ON property_ical_sources (property_id);


-- 9. IMPORTED CALENDAR EVENTS (events parsed from synced iCal feeds)
CREATE TABLE IF NOT EXISTS imported_calendar_events (
  id               BIGINT AUTO_INCREMENT PRIMARY KEY,
  property_id      INT NOT NULL,
  external_uid     VARCHAR(255) NOT NULL,
  source_provider  VARCHAR(50) NOT NULL
                   CHECK (source_provider IN ('airbnb', 'booking', 'vrbo')),
  start_date       DATE NOT NULL,
  end_date         DATE NOT NULL,
  summary          TEXT,
  last_seen_at     TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_at       TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,

  CONSTRAINT fk_imported_calendar_events_property
      FOREIGN KEY (property_id) REFERENCES properties(id) ON DELETE CASCADE,
  CONSTRAINT end_after_start CHECK (end_date >= start_date),
  CONSTRAINT unique_external_event UNIQUE (external_uid, property_id, source_provider)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_imported_calendar_events_property_dates
  ON imported_calendar_events (property_id, start_date, end_date);
CREATE INDEX idx_imported_calendar_events_provider
  ON imported_calendar_events (property_id, source_provider);


-- 10. PRICING TIERS (seasonal/single-day/weekend/yearly overrides by property
-- name — queried by PricingController, though not yet wired into routes.php)
--
-- The Postgres version upserted against two different conflict targets
-- depending on tier_type: (property_name, tier_type, specific_date) for
-- 'single_day' rows, and (property_name, tier_type) for 'weekend'/'yearly'
-- rows (achievable there via two partial unique indexes). MySQL has no
-- partial/filtered unique index, so a generated column collapses both
-- rules into one real unique key: specific_date is only meaningful for
-- 'single_day', so non-single_day rows are normalized to a constant
-- sentinel date, making (property_name, tier_type, specific_date_key)
-- enforce "one row per date" for single_day and "one row per type" for
-- the other two.
CREATE TABLE IF NOT EXISTS pricing_tiers (
  id                BIGINT AUTO_INCREMENT PRIMARY KEY,
  property_name     VARCHAR(255) NOT NULL,
  tier_type         VARCHAR(20) NOT NULL
                    CHECK (tier_type IN ('single_day', 'weekend', 'yearly')),
  specific_date     DATE NULL,
  base_price        DECIMAL(10,2) NOT NULL,
  extra_person_fee  DECIMAL(10,2),
  created_at        TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at        TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  specific_date_key DATE GENERATED ALWAYS AS
                    (COALESCE(specific_date, '0001-01-01')) STORED,

  CONSTRAINT fk_pricing_tiers_property_name
      FOREIGN KEY (property_name) REFERENCES properties(name),
  CONSTRAINT unique_pricing_tier UNIQUE (property_name, tier_type, specific_date_key)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
